using Microsoft.Extensions.Options;using ScraperBackendService.Configuration;using ScraperBackendService.Core.Logging;using System.Security.Cryptography;using System.Text;namespace ScraperBackendService.Middleware;/// <summary>/// Token authentication middleware for securing API endpoints./// Validates authentication tokens for API requests when authentication is enabled./// </summary>public sealed class TokenAuthenticationMiddleware{    private readonly RequestDelegate _next;    private readonly ServiceConfiguration _config;    private readonly ILogger<TokenAuthenticationMiddleware> _logger;    public TokenAuthenticationMiddleware(        RequestDelegate next,        IOptions<ServiceConfiguration> config,        ILogger<TokenAuthenticationMiddleware> logger)    {        _next = next;        _config = config.Value;        _logger = logger;    }    public async Task InvokeAsync(HttpContext context)    {        if (string.IsNullOrWhiteSpace(_config.AuthToken))        {            await _next(context);            return;        }        if (context.Request.Path == "/" || context.Request.Path == "/health")        {            await _next(context);            return;        }        if (context.Request.Path.StartsWithSegments("/api") ||            context.Request.Path.StartsWithSegments("/cache"))        {            var token = context.Request.Headers[_config.TokenHeaderName].FirstOrDefault();            if (string.IsNullOrWhiteSpace(token))            {                _logger.LogWarning("Authentication", "Missing token", context.Connection.RemoteIpAddress?.ToString());                context.Response.StatusCode = 401;                await context.Response.WriteAsync("Missing authentication token");                return;            }            if (!IsValidToken(token, _config.AuthToken!))            {                _logger.LogWarning("Authentication", "Invalid token", context.Connection.RemoteIpAddress?.ToString());                context.Response.StatusCode = 401;                await context.Response.WriteAsync("Invalid authentication token");                return;            }            _logger.LogDebug("Authentication", "Token validated", context.Connection.RemoteIpAddress?.ToString());        }        await _next(context);    }    private static bool IsValidToken(string candidateToken, string configuredToken)    {        var left = Encoding.UTF8.GetBytes(candidateToken);        var right = Encoding.UTF8.GetBytes(configuredToken);        return CryptographicOperations.FixedTimeEquals(left, right);    }}